const now = new Date();
const today = now.toISOString().slice(0, 10);
const thirtyDaysAgo = new Date(now - 30 * 24 * 60 * 60 * 1000).toISOString().slice(0, 10);

// ── CONFIDENCE THRESHOLDS ─────────────────────────────────────────────────────
// AUTO_APPLY: Claude's category suggestion is applied automatically
// AUTO_RULE:  Category applied AND a permanent payee rule is created in Actual
//             (that payee will never be sent to Claude again)
// Below AUTO_APPLY: Telegram alert for manual review
const AUTO_APPLY_THRESHOLD = 0.85;
const AUTO_RULE_THRESHOLD  = 0.95;

// ── CATEGORIES ───────────────────────────────────────────────────────────────
// HOW TO FILL THIS IN:
//   1. Run Workflow 00 (Discovery) to get your category IDs
//   2. Replace each 'GET_FROM_WF00' with the actual ID from Discovery output
//   3. Update names to match your Actual Budget category names exactly
//   4. Add or remove rows to match your category setup
//
// Names are sent to Claude as context — make them descriptive so Claude
// can categorize accurately without needing merchant-specific training.
const categories = [
  { id: 'GET_FROM_WF00', name: 'Mortgage or rent payment' },
  { id: 'GET_FROM_WF00', name: 'Car loan payment' },
  { id: 'GET_FROM_WF00', name: 'Personal loan payment' },
  { id: 'GET_FROM_WF00', name: 'Extra debt payment' },
  { id: 'GET_FROM_WF00', name: 'Emergency fund savings' },
  { id: 'GET_FROM_WF00', name: 'Internet bill' },
  { id: 'GET_FROM_WF00', name: 'Gas utility bill' },
  { id: 'GET_FROM_WF00', name: 'Electric utility bill' },
  { id: 'GET_FROM_WF00', name: 'Water bill' },
  { id: 'GET_FROM_WF00', name: 'Cell phone or mobile phone bill' },
  { id: 'GET_FROM_WF00', name: 'Streaming services subscription' },
  { id: 'GET_FROM_WF00', name: 'Home improvement or maintenance' },
  { id: 'GET_FROM_WF00', name: 'Gas station or fuel' },
  { id: 'GET_FROM_WF00', name: 'Auto insurance premium' },
  { id: 'GET_FROM_WF00', name: 'Car repair or maintenance' },
  { id: 'GET_FROM_WF00', name: 'Parking tolls rideshare transit' },
  { id: 'GET_FROM_WF00', name: 'Groceries supermarket warehouse club' },
  { id: 'GET_FROM_WF00', name: 'Restaurants fast food coffee shops delivery' },
  { id: 'GET_FROM_WF00', name: 'Financial advisor or planning fee' },
  { id: 'GET_FROM_WF00', name: 'Doctor pharmacy medical gym fitness' },
  { id: 'GET_FROM_WF00', name: 'Haircut salon barber personal grooming' },
  { id: 'GET_FROM_WF00', name: 'Clothing shoes apparel' },
  { id: 'GET_FROM_WF00', name: 'Entertainment hobbies events tickets' },
  { id: 'GET_FROM_WF00', name: 'Gifts for others birthday holiday' },
  { id: 'GET_FROM_WF00', name: 'Pet food vet grooming supplies' },
  { id: 'GET_FROM_WF00', name: 'Vacation travel hotel flights' },
  { id: 'GET_FROM_WF00', name: 'Kids activities school fees sports' },
  { id: 'GET_FROM_WF00', name: 'Amazon or online shopping' },
  { id: 'GET_FROM_WF00', name: 'Miscellaneous hard to categorize' },
];

return [{
  json: {
    bridgeUrl:        'http://actual-bridge:3788',
    telegramChatId:   'REPLACE_WITH_YOUR_TELEGRAM_CHAT_ID',
    categories,
    AUTO_APPLY_THRESHOLD,
    AUTO_RULE_THRESHOLD,
    startDate: thirtyDaysAgo,
    endDate: today
  }
}];

const res = $input.item.json;
const config = $('Config').item.json;
const txList = res.data || [];

if (txList.length === 0) {
  return [];
}

// Filter out anything that shouldn't reach Claude
const filtered = txList.filter(tx =>
  tx.amount < 0 &&
  !tx.starting_balance_flag &&
  !tx.transfer_id &&
  !tx.is_parent
);

if (filtered.length === 0) {
  return [];
}

const categoryList = config.categories
  .map(c => c.name)
  .join('\n');

return filtered.map(tx => ({
  json: {
    ...config,
    transaction: tx,
    amount: Math.abs(tx.amount) / 100,
    categoryList
  }
}));

const claudeRes = $input.item.json;
const txData = $('Filter Uncategorized').item.json;

let parsed;
try {
  const raw = claudeRes.content && claudeRes.content[0] ? claudeRes.content[0].text : '{}';
  const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = { category: null, confidence: 0, reason: 'Parse error: ' + e.message };
}

const matched = txData.categories.find(
  function(c) { return c.name.toLowerCase() === (parsed.category || '').toLowerCase(); }
);

return {
  json: {
    ...txData,
    suggestedName: parsed.category,
    suggestedId: matched ? matched.id : null,
    confidence: parsed.confidence || 0,
    reason: parsed.reason || ''
  }
};

const items = $input.all();
const config = $('Parse Response').item.json;
const lowConfidence = [];

for (const item of items) {
  const d = item.json;
  const payee = d.transaction.imported_payee || d.transaction.payee_name || 'Unknown';
  lowConfidence.push(
    payee + ' — $' + d.amount.toFixed(2) + '\n' +
    '  Suggested: ' + (d.suggestedName || 'None') + ' (' + Math.round((d.confidence || 0) * 100) + '%)' + '\n' +
    '  Reason: ' + (d.reason || '') + '\n' +
    '  Date: ' + d.transaction.date + ' | Acct: ' + (d.transaction.accountName || '')
  );
}

if (lowConfidence.length === 0) return [];

const msg = lowConfidence.length + ' transaction(s) need your review:\n\n' +
  lowConfidence.join('\n\n') + '\n\n' +
  'Open Actual to categorize: http://your-actual-budget-url';

return [{ json: {
  telegramChatId: config.telegramChatId,
  telegramMessage: msg
} }];
